import { useEffect, useMemo, useState } from 'react';
import type { SelectOption } from '@linm-soft-org/linm-web-common-components';
import { voucherInitService, type ErpFormInitData, type FormActionPermissions, type AccountDefaultDto } from '../services/voucherInit/endpoint';
import { mapAccountDefault, type AccountDefault } from '../utils/voucherAccountDefaults';
import { getApiErrorMessage } from '../utils/getApiErrorMessage';

const EMPTY: SelectOption[] = [];
const toOpts = (items?: FormOption[]): SelectOption[] =>
  (items ?? []).map(o => ({ value: o.value, label: o.label }));

type FormOption = { value: string; label: string };

export function useVoucherInitData(formName: string) {
  const [data, setData] = useState<ErpFormInitData | null>(null);
  const [loading, setLoading] = useState(true);
  const [initError, setInitError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setInitError(null);
    const timer = setTimeout(() => {
      if (cancelled) return;
      voucherInitService
        .getInitData(formName)
        .then(d => { if (!cancelled) setData(d); })
        .catch(err => { if (!cancelled) setInitError(getApiErrorMessage(err, 'Không thể tải dữ liệu cấu hình form.')); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [formName]);

  const materialGroupOptions = useMemo(() => toOpts(data?.materialGroupOptions), [data?.materialGroupOptions]);
  const partnerGroupOptions = useMemo(() => toOpts(data?.partnerGroupOptions), [data?.partnerGroupOptions]);
  const unitOptions = useMemo(() => toOpts(data?.unitOptions), [data?.unitOptions]);
  const taxRateOptions = useMemo(() => toOpts(data?.taxRateOptions), [data?.taxRateOptions]);
  const currencyOptions = useMemo(() => toOpts(data?.currencyOptions), [data?.currencyOptions]);
  const warehouseOptions = useMemo(() => toOpts(data?.warehouseOptions), [data?.warehouseOptions]);
  const departmentOptions = useMemo(() => toOpts(data?.departmentOptions), [data?.departmentOptions]);
  const voucherStatusOptions = useMemo(() => toOpts(data?.voucherStatusOptions), [data?.voucherStatusOptions]);
  const purchaseInvoiceTypeOptions = useMemo(
    () => toOpts(data?.purchaseInvoiceTypeOptions),
    [data?.purchaseInvoiceTypeOptions],
  );
  const processingLevelOptions = useMemo(
    () => toOpts(data?.processingLevelOptions),
    [data?.processingLevelOptions],
  );
  const journalEntryTypeOptions = useMemo(
    () => toOpts(data?.journalEntryTypeOptions),
    [data?.journalEntryTypeOptions],
  );
  const customerGroupOptions = useMemo(() => toOpts(data?.customerGroupOptions), [data?.customerGroupOptions]);
  const mapDefault = (dto?: AccountDefaultDto): AccountDefault | null => mapAccountDefault(dto);
  const defaultAccount = useMemo(() => mapDefault(data?.defaultAccount), [data?.defaultAccount]);
  const defaultCreditAccount = useMemo(() => mapDefault(data?.defaultCreditAccount), [data?.defaultCreditAccount]);
  const defaultVatAccount = useMemo(() => mapDefault(data?.defaultVatAccount), [data?.defaultVatAccount]);
  const defaultDebitAccount = useMemo(() => mapDefault(data?.defaultDebitAccount), [data?.defaultDebitAccount]);
  const defaultFixedAssetAccount = useMemo(() => mapDefault(data?.defaultFixedAssetAccount), [data?.defaultFixedAssetAccount]);
  const defaultDepreciationExpenseAccount = useMemo(
    () => mapDefault(data?.defaultDepreciationExpenseAccount),
    [data?.defaultDepreciationExpenseAccount],
  );
  const defaultAccumDepreciationAccount = useMemo(
    () => mapDefault(data?.defaultAccumDepreciationAccount),
    [data?.defaultAccumDepreciationAccount],
  );
  const defaultCurrencyCode = data?.defaultCurrencyCode;
  const defaultExchangeRate = data?.defaultExchangeRate;
  const currencyExchangeRates = useMemo(
    () => data?.currencyExchangeRates ?? [],
    [data?.currencyExchangeRates],
  );
  const postingReasonRules = useMemo(
    () => data?.postingReasonRules ?? [],
    [data?.postingReasonRules],
  );
  const paymentChannels = useMemo(
    () => data?.paymentChannels ?? [],
    [data?.paymentChannels],
  );
  const receiptTypeConfigs = useMemo(
    () => data?.receiptTypeConfigs ?? [],
    [data?.receiptTypeConfigs],
  );

  return {
    loading,
    initError,
    materialGroupOptions,
    partnerGroupOptions,
    unitOptions,
    taxRateOptions,
    currencyOptions,
    warehouseOptions,
    departmentOptions,
    voucherStatusOptions,
    purchaseInvoiceTypeOptions,
    processingLevelOptions,
    defaultProcessingLevel: data?.defaultProcessingLevel,
    defaultCurrencyCode,
    defaultExchangeRate,
    currencyExchangeRates,
    journalEntryTypeOptions,
    customerGroupOptions,
    defaultAccount,
    defaultCreditAccount,
    defaultVatAccount,
    defaultDebitAccount,
    defaultFixedAssetAccount,
    defaultDepreciationExpenseAccount,
    defaultAccumDepreciationAccount,
    formPermissions: data?.formPermissions ?? null,
    postingReasonRules,
    paymentChannels,
    fieldDefaults: data?.fieldDefaults,
    receiptTypeConfigs,
    raw: data,
  };
}

export type { FormActionPermissions };
